/**
 * documentTemplate.ts
 * Template de documento reutilizável — cabeçalho com logo + rodapé com linha e contactos.
 * Usado por: Notas de Despesa, Orçamentos, e qualquer outro documento emitido pela app.
 *
 * Localização sugerida: client/src/lib/documentTemplate.ts
 *
 * Uso:
 *   import { applyDocumentTemplate, CONTENT_START_Y, PAGE_WIDTH, MARGIN } from "@/lib/documentTemplate";
 *   const doc = new jsPDF();
 *   applyDocumentTemplate(doc);
 *   // conteúdo começa em CONTENT_START_Y
 */

import jsPDF from "jspdf";

// ── Dimensões A4 em mm ──────────────────────────────────────
export const PAGE_WIDTH = 210;
export const PAGE_HEIGHT = 297;
export const MARGIN = 15;
export const CONTENT_WIDTH = PAGE_WIDTH - MARGIN * 2;

// ── Posições fixas ──────────────────────────────────────────
// Logo: canto superior direito, 30mm × 30mm
const LOGO_SIZE = 30;
const LOGO_X = PAGE_WIDTH - MARGIN - LOGO_SIZE;
const LOGO_Y = 10;

// Conteúdo começa abaixo do cabeçalho
export const CONTENT_START_Y = LOGO_Y + LOGO_SIZE + 8;

// Rodapé: linha verde + texto
const FOOTER_LINE_Y = PAGE_HEIGHT - 18;
const FOOTER_TEXT_Y = PAGE_HEIGHT - 11;
const FOOTER_COLOR: [number, number, number] = [83, 129, 53]; // #538135

// Logo em base64 (PNG extraído do carta_template.dotx)
const LOGO_BASE64 =
  "data:image/png;base64,";

/**
 * Aplica o template (cabeçalho + rodapé) a TODAS as páginas do documento.
 * Chamar DEPOIS de adicionar todo o conteúdo para garantir que cobre todas as páginas.
 */
export function applyDocumentTemplate(doc: jsPDF): void {
  const totalPages = doc.getNumberOfPages();

  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i);
    _drawHeader(doc);
    _drawFooter(doc);
  }
}

/**
 * Aplica o template à página actual apenas.
 * Útil quando se adiciona conteúdo página a página.
 */
export function applyTemplateToCurrentPage(doc: jsPDF): void {
  _drawHeader(doc);
  _drawFooter(doc);
}

function _drawHeader(doc: jsPDF): void {
  try {
    doc.addImage(LOGO_BASE64, "PNG", LOGO_X, LOGO_Y, LOGO_SIZE, LOGO_SIZE);
  } catch {
    // Se o logo falhar, não quebra o documento
    console.warn("documentTemplate: falha ao carregar logo");
  }
}

function _drawFooter(doc: jsPDF): void {
  // Linha verde
  doc.setDrawColor(...FOOTER_COLOR);
  doc.setLineWidth(0.8);
  doc.line(MARGIN, FOOTER_LINE_Y, PAGE_WIDTH - MARGIN, FOOTER_LINE_Y);

  // Texto centrado
  doc.setFont("helvetica", "normal");
  doc.setFontSize(8);
  doc.setTextColor(...FOOTER_COLOR);
  doc.text(
    "Tiago Santos – 918 297 502   ·   peraltagardens@gmail.com",
    PAGE_WIDTH / 2,
    FOOTER_TEXT_Y,
    { align: "center" }
  );

  // Reset cores para não afectar conteúdo seguinte
  doc.setDrawColor(0);
  doc.setTextColor(0);
}
